import { app, BrowserWindow, ipcMain, session } from 'electron';
import path from 'path';
import os from 'os';
import fs from 'fs';
import { spawn } from 'child_process';
import { fileURLToPath } from 'url';
import pkg from 'electron-updater';
const { autoUpdater } = pkg;

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ═══════════════════════════════════════════════════════════
// Embedded Scripts — decoded at runtime, never stored on disk
// ═══════════════════════════════════════════════════════════
const _S = {
    'scripts/clear_browser.ps1': '',
    'scripts/clear_winhistory.ps1': '',
    'scripts/clear_tempfiles.ps1': '',
    'scripts/disk_cleanup.ps1': '',
    'scripts/network_optimize.ps1': '',
    'scripts/flush_dns.ps1': '',
    'scripts/cpu_optimize.ps1': '',
    'scripts/gpu_optimize.ps1': '',
    'scripts/inject_fps.ps1': '',
    'scripts/inject_fps_ultracore.ps1': ''

};

function _d(k) {
    const b = _S[k];
    if (!b) return null;
    return Buffer.from(b, 'base64').toString('utf8');
}

let mainWindow;

function createWindow() {
    mainWindow = new BrowserWindow({
        width: 960,
        height: 640,
        resizable: false,
        titleBarStyle: 'hidden',
        titleBarOverlay: {
            color: '#1a1a1a',
            symbolColor: '#ffffff',
        },
        webPreferences: {
            preload: path.join(__dirname, 'preload.cjs'),
            nodeIntegration: false,
            contextIsolation: true,
            webSecurity: true,
            devTools: !app.isPackaged
        },
        autoHideMenuBar: true,
    });

    if (process.env.NODE_ENV === 'development' || !app.isPackaged) {
        mainWindow.loadURL('http://localhost:5173');
    } else {
        mainWindow.loadFile(path.join(__dirname, 'dist', 'index.html'));

        // ═══ Anti-Debug: Block DevTools in production ═══
        mainWindow.webContents.on('devtools-opened', () => {
            mainWindow.webContents.closeDevTools();
        });

        // Block F12 and Ctrl+Shift+I
        mainWindow.webContents.on('before-input-event', (event, input) => {
            if (input.key === 'F12' ||
                (input.control && input.shift && input.key === 'I') ||
                (input.control && input.shift && input.key === 'J') ||
                (input.control && input.key === 'u')) {
                event.preventDefault();
            }
        });
    }
}

app.whenReady().then(() => {
    createWindow();
    autoUpdater.checkForUpdatesAndNotify();

    // ═══ Auto-Updater Events ═══
    autoUpdater.on('checking-for-update', () => {
        mainWindow?.webContents.send('update-status', { status: 'checking' });
    });
    autoUpdater.on('update-available', (info) => {
        mainWindow?.webContents.send('update-status', { status: 'available', version: info.version });
    });
    autoUpdater.on('update-not-available', () => {
        mainWindow?.webContents.send('update-status', { status: 'up-to-date' });
    });
    autoUpdater.on('download-progress', (progress) => {
        mainWindow?.webContents.send('update-status', { status: 'downloading', percent: Math.round(progress.percent) });
    });
    autoUpdater.on('update-downloaded', (info) => {
        mainWindow?.webContents.send('update-status', { status: 'downloaded', version: info.version });
    });
    autoUpdater.on('error', (err) => {
        mainWindow?.webContents.send('update-status', { status: 'error', message: err?.message });
    });

    // IPC: User wants to install update now
    ipcMain.on('install-update', () => {
        autoUpdater.quitAndInstall();
    });

    // ═══ CSP — Block inline scripts & unauthorized origins ═══
    session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
        callback({
            responseHeaders: {
                ...details.responseHeaders,
                'Content-Security-Policy': [
                    "default-src 'self'; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'; connect-src 'self' https://candyxofficial.com https://candyxstore.com; img-src 'self' data: https://starxlevelup.net https://image.api.playstation.com https://cdn.akamai.steamstatic.com https://assets.aceternity.com; font-src 'self' data:;"
                ]
            }
        });
    });

    // ═══ Navigation Guard — Block redirect to external sites ═══
    mainWindow.webContents.on('will-navigate', (event, url) => {
        if (!url.startsWith('file://') && !url.startsWith('http://localhost')) {
            event.preventDefault();
        }
    });
    mainWindow.webContents.setWindowOpenHandler(() => ({ action: 'deny' }));

    // ═══ Permission Handler — Deny all unnecessary permissions ═══
    session.defaultSession.setPermissionRequestHandler((_webContents, _permission, callback) => {
        callback(false);
    });

    app.on('activate', () => {
        if (BrowserWindow.getAllWindows().length === 0) createWindow();
    });
});

app.on('window-all-closed', () => {
    if (process.platform !== 'darwin') app.quit();
});

// IPC Handler to run PowerShell scripts
ipcMain.handle('run-script', async (event, scriptPath, injectedInput) => {
    return new Promise((resolve, reject) => {
        try {
            let content;
            const embedded = _d(scriptPath);

            if (embedded) {
                // Use embedded (production & dev)
                content = embedded;
            } else if (fs.existsSync(scriptPath)) {
                // Fallback: read from disk (dev mode for non-embedded scripts)
                content = fs.readFileSync(scriptPath, 'utf8');
            } else {
                // Try relative to app dir
                const resolved = path.join(__dirname, scriptPath);
                if (fs.existsSync(resolved)) {
                    content = fs.readFileSync(resolved, 'utf8');
                } else {
                    reject('Script not found: ' + scriptPath);
                    return;
                }
            }

            const inputStr = injectedInput !== undefined ? injectedInput.toString() : '1';

            // Sanitize script content
            content = content.replace(/If \(!\(\[Security\.Principal\.WindowsPrincipal\].*?\{Start-Process PowerShell\.exe.*?Exit\}/gis, '');
            content = content.replace(/\$Host\.UI\.RawUI\..*?\n/gi, '');
            content = content.replace(/\$Host\.PrivateData\..*?\n/gi, '');
            content = content.replace(/Clear-Host/gi, '');
            content = content.replace(/.*?\$Host\.UI\.RawUI\.ReadKey.*?\n/gi, '');
            content = content.replace(/Read-Host[^\n]*\n?/gi, `"${inputStr}"\n`);
            content = content.replace(/pause\n?/gi, '');
            content = content.replace(/Start-Process\s+explorer[^\n]*\n?/gi, '');
            content = content.replace(/Start-Process\s+ms-settings[^\n]*\n?/gi, '');
            content = content.replace(/Start-Process\s+diskmgmt[^\n]*\n?/gi, '');

            // Write to temp, run, then delete
            const tempFile = path.join(os.tmpdir(), `cx_${Date.now()}_${Math.random().toString(36).slice(2, 8)}.ps1`);
            fs.writeFileSync(tempFile, content, 'utf8');

            const ps = spawn(
                'powershell.exe',
                ['-NoProfile', '-NonInteractive', '-WindowStyle', 'Hidden', '-ExecutionPolicy', 'Bypass', '-File', tempFile],
                {
                    cwd: os.tmpdir(),
                    windowsHide: true,
                    shell: true,
                    env: { ...process.env }
                }
            );

            ps.stdout.on('data', (data) => {
                if (mainWindow) mainWindow.webContents.send('script-output', data.toString());
            });

            ps.stderr.on('data', (data) => {
                if (mainWindow) mainWindow.webContents.send('script-output', `\nERROR: ${data.toString()}`);
            });

            ps.on('close', (code) => {
                try { fs.unlinkSync(tempFile); } catch (e) { }
                resolve(`\n\nProcess exited with code ${code}\n`);
            });

            ps.on('error', (err) => {
                try { fs.unlinkSync(tempFile); } catch (e) { }
                reject(err.message);
            });
        } catch (e) {
            reject(e.message);
        }
    });
});

// Save license key to registry
ipcMain.handle('save-license-key', async (_event, key) => {
    return new Promise((resolve) => {
        const sanitized = key.replace(/[^a-zA-Z0-9\-]/g, '');
        const regPath = sanitized.toUpperCase().startsWith('ACCESS')
            ? 'HKCU\\SOFTWARE\\boostfps2'
            : 'HKCU\\SOFTWARE\\boostfps';
        const ps = spawn('reg', ['add', regPath, '/v', 'key', '/t', 'REG_SZ', '/d', sanitized, '/f'], { windowsHide: true, shell: true });
        ps.on('close', () => resolve(true));
        ps.on('error', () => resolve(false));
    });
});

ipcMain.handle('get-base-dir', () => {
    return path.join(__dirname, '..');
});

ipcMain.handle('get-scripts', () => {
    const baseDir = path.join(__dirname, '..');
    const items = fs.readdirSync(baseDir, { withFileTypes: true });
    const result = [];

    for (const item of items) {
        if (item.isDirectory() && !item.name.startsWith('.') && item.name !== 'Windows-Optimizer-App' && /^\d+\s/.test(item.name)) {
            const folderPath = path.join(baseDir, item.name);
            const scriptFiles = fs.readdirSync(folderPath)
                .filter(f => f.endsWith('.ps1'))
                .map(f => ({ name: f.replace('.ps1', ''), file: f, path: path.join(folderPath, f) }));

            if (scriptFiles.length > 0) {
                result.push({
                    category: item.name,
                    scripts: scriptFiles
                });
            }
        }
    }

    const gamesBaseDir = path.join(baseDir, 'Github-Game-Configs-main');
    if (fs.existsSync(gamesBaseDir)) {
        const gameFolders = fs.readdirSync(gamesBaseDir, { withFileTypes: true });
        const gameScripts = [];

        for (const gf of gameFolders) {
            if (gf.isDirectory()) {
                const innerPath = path.join(gamesBaseDir, gf.name);
                const ps1Files = fs.readdirSync(innerPath).filter(f => f.endsWith('.ps1'));
                for (const file of ps1Files) {
                    gameScripts.push({
                        name: file.replace('.ps1', ''),
                        file: file,
                        path: path.join(innerPath, file),
                        isGame: true
                    });
                }
            }
        }

        if (gameScripts.length > 0) {
            result.push({
                category: '9 Games',
                scripts: gameScripts
            });
        }
    }

    return result;
});
